<?php
namespace App\Controllers;
use App\Core\Controller;use App\Models\Repository;
final class HomeController extends Controller {public function index():void{$r=new Repository;$db=$r->db();$songs=$db->query("SELECT c.*,COALESCE(a.nombre,b.nombre,'Sin artista') artista,g.nombre genero FROM canciones c LEFT JOIN artistas a ON a.id=c.artista_id LEFT JOIN bandas b ON b.id=c.banda_id LEFT JOIN generos g ON g.id=c.genero_id WHERE c.estado=1 ORDER BY c.id DESC")->fetchAll();$top=$db->query("SELECT * FROM vw_top_canciones_30_dias LIMIT 10")->fetchAll();$artist=$db->query("SELECT COALESCE(a.nombre,b.nombre,'Sin artista') artista,COUNT(r.id) total FROM reproducciones r JOIN canciones c ON c.id=r.cancion_id LEFT JOIN artistas a ON a.id=c.artista_id LEFT JOIN bandas b ON b.id=c.banda_id WHERE r.fecha_hora>=DATE_SUB(NOW(),INTERVAL 30 DAY) GROUP BY artista ORDER BY total DESC LIMIT 1")->fetch()?:null;$events=$db->query("SELECT e.*,l.nombre local_nombre FROM eventos e LEFT JOIN locales l ON l.id=e.local_id WHERE e.estado=1 AND e.fecha>=CURDATE() ORDER BY e.fecha,e.hora LIMIT 8")->fetchAll();$artists=$db->query("SELECT * FROM artistas WHERE estado=1 ORDER BY nombre")->fetchAll();$bands=$db->query("SELECT * FROM bandas WHERE estado=1 ORDER BY nombre")->fetchAll();$venues=$db->query("SELECT * FROM locales WHERE estado=1 ORDER BY nombre")->fetchAll();$plans=$db->query("SELECT * FROM planes WHERE estado=1 ORDER BY precio")->fetchAll();$this->view('public/home',compact('songs','top','artist','events','artists','bands','venues','plans'));}}
